// // This module converts a 4-bit binary input to its corresponding 4-bit Gray code output, with the least significant bit being the same as that of the binary input.
module top_module(
  input [3:0] binary,
  output reg [3:0] gray
);always @* begin
    gray[3] = binary[3];
    gray[2] = binary[3] ^ binary[2];
    gray[1] = binary[2] ^ binary[1];
    gray[0] = binary[1] ^ binary[0];
  end

endmodule
